#include <iostream>
using namespace std;

class Shape {
public:
  void setColor(string c) { color = c; }
  string getColor() { return color; }
private:
  string color;
};

class Circle : public Shape {
public:
  double radius;
  double area() { return 3.14159 * radius * radius; }
};

int main() {
  Circle c;
  c.setColor("Red");
  c.radius = 5.0;
  cout << "Color: " << c.getColor() << ", Area: " << c.area() << endl;
  return 0;
}
